window.__QUIZ_DATA__=[{"id":"objective>Computer Studies>2014>1","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"The first calculator was built by","images":[],"options":{"A":"Marie Jacquad","B":"Balise Pascal","C":"Charles Babbage","D":"John Napier"},"answer":"B","explanation":"Blaise Pascal  The first calculator or adding machine to be produced in any quantity and actually used was the Pascaline, or Arithmetic Machine, designed and built by the French mathematician-philosopher Blaise Pascal between 1642 and 1644.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>2","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"A similarity between data and information is that both","images":[],"options":{"A":"can be displayed on the monitor","B":"are computer inputs","C":"are processed facts","D":"are computer results"},"answer":"A","explanation":"Both data and information can be displayed on a monitor. Data refers to raw, unprocessed, and unorganized facts or details that alone might not make much sense. Information, on the other hand, is processed data; it is data that has been given a context and is useful to the user.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>3","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"The computer hardware can be classified into","images":[],"options":{"A":"ALU and Control Unit","B":"System Unit and Peripheral","C":"Central Processing Unit and Control Unit","D":"Input and Output Units"},"answer":"B","explanation":"The computer hardware is classified into System Unit and Peripheral","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>4","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION AGE : DATA AND INFORMATION","question":"The outcome of a processed data in a computer is known as","images":[],"options":{"A":"raw fact","B":"information","C":"database","D":"computer result"},"answer":"B","explanation":"The outcome of a processed data in a computer is known as 'information'. Raw data is processed by a computer and turned into a meaningful output, which is referred to as information. This is the fundamental concept of data processing.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>5","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Which of the following devices is not a micro computer?","images":[],"options":{"A":"Notebook","B":"Laptop","C":"EDVAC","D":"Desktop"},"answer":"C","explanation":"EDVAC (Electronic Discrete Variable Automatic Computer) was one of the earliest electronic computers. It is not a micro computer.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>6","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"Which of the following computing devices did not exist in the pre-computing age to the 19th century?","images":[],"options":{"A":"Napier's bone","B":"Abacus","C":"ENIAC","D":"Slide Rule"},"answer":"C","explanation":"ENIAC (Electronic Numerical Integrator and Computer) is considered to be the first operational digital computer in USA, developed by Army ordinance to compute World War II ballistic firing tables.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>7","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION AGE : HISTORY OF COMPUTERS","question":"The computing devices invented by Charles Babbage are","images":[],"options":{"A":"Difference Engine and Abacus","B":"Analytical Engine and Slide Rule","C":"Abacus and Slide Rule","D":"Analytical and Difference Engines"},"answer":"D","explanation":"Charles Babbage, an English mechanical engineer and polymath, originated the concept of a digital programmable computer. He invented two computing devices which are known as the Analytical Engine and the Difference Engine.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>8","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"In a computer, the sets of instruction that direct it in performing a particular task is called","images":[],"options":{"A":"information","B":"program","C":"data","D":"file"},"answer":"B","explanation":"In a computer, a program is a set of instructions that direct the computer to perform a particular task. These instructions are written in a programming language that the computer can understand and execute.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>9","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The property of a disk that determines the amount of data it may contain is","images":[],"options":{"A":"size","B":"volume","C":"storage capacity","D":"storage power"},"answer":"C","explanation":"The property of a disk that determines the amount of data it may contain is its storage capacity. This is usually measured in bytes and its multiples (KB, MB, GB, TB, etc.). The size and volume of a disk do not necessarily determine its storage capacity, and 'storage power' is not a recognized term in this context.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>10","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Which of the following items best describes the term hardcopy?","images":[],"options":{"A":"Print out","B":"Written on a hard board","C":"Information stored on a hard disk","D":"Amount of data"},"answer":"A","explanation":"A hardcopy refers to a printed document or material that is in a physical form. It is a physical version of a digital document. Therefore, the term 'hardcopy' is best described as a 'Print out'.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>11","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Which of the following is not an output device?","images":[],"options":{"A":"Plotters","B":"Speakers","C":"Projectors","D":"Webcams"},"answer":"D","explanation":"An output device is any piece of computer hardware equipment which converts information into human-readable form. Plotters, Speakers, and Projectors are all output devices as they display or produce output from the computer. However, Webcams are input devices because they capture and send data to the computer, rather than receiving and displaying data.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>12","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Which of the following signifies the correct association between a hardware component and its function?","images":[],"options":{"A":"Mouse to input","B":"Monitor to print","C":"CPU to storage","D":"Hard disk to processing"},"answer":"A","explanation":"A hardware component's function is defined by what it does in a computer system. A mouse is an input device used to input data into the computer. A monitor is used to display information, but it does not print. The CPU (Central Processing Unit) is the main processing unit of a computer, but it does not store data. The hard disk is used for storage, not for processing. Therefore, the correct association between a hardware component and its function is 'Mouse to input'.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>13","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Fig. 1 is a logic gate. Use it to answer this question.      Fig. 1 represents","images":["data:image/png;base64,"],"options":{"A":"an AND gate","B":"an OR gate","C":"a NOT gae","D":"a NAND gate"},"answer":"B","explanation":"The diagram labeled Fig. 1 illustrates an OR gate, a fundamental logic gate used in digital circuits. An OR gate produces a high output (1) if any of its inputs are high (1). It acts as a logical OR operation, returning true if any of its inputs are true.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>14","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Fig. 1 is a logic gate. Use it to answer this question.    In Fig. 1, X, Y and Z respectively represent","images":["data:image/png;base64,"],"options":{"A":"input, output and input signals","B":"output, output and input signals","C":"output, input and output signals","D":"input, input and output signals"},"answer":"D","explanation":"In the diagram labeled Fig. 1, X and Y represent the input variables, while Z represents the output variable. This indicates that the OR gate takes X and Y as inputs and produces Z as the output, based on the logical OR operation.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>15","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : DATABASE MANAGEMENT SYSTEM","question":"Which of the following software is best suitable for keeping records during national population census?","images":[],"options":{"A":"Word Processing","B":"Spreadfast","C":"Graphic","D":"Database"},"answer":"D","explanation":"Database software is best suitable for keeping records during a national population census. This is because a database is designed to store, retrieve, define, and manage large amounts of data, making it an ideal tool for tasks that involve storing and manipulating large amounts of information, like a national population census.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>16","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"A major function of system software is","images":[],"options":{"A":"collection of files","B":"translation of machine language into machine code","C":"file management","D":"arrangement of files in ascending order"},"answer":"C","explanation":"The three major functions of system software are allocating system resources, monitoring system activities, and disk and file management.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>17","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : OPERATING SYSTEM","question":"An advantage of Graphical User Interface (GUI) over Disk Operating System (DOC) is that it allows the use of","images":[],"options":{"A":"diskette","B":"keyboard","C":"mouse","D":"monitor"},"answer":"C","explanation":"An advantage of Graphical User Interface (GUI) over Disk Operating System (DOS) is that it allows the use of a mouse. GUI is a type of user interface that allows users to interact with electronic devices through graphical icons and visual indicators, as opposed to text-based interfaces, typed command labels or text navigation. One of the main advantages of GUI is the use of a mouse to navigate and interact with the system, which is not typically available in DOS.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>18","subject":"Computer Studies","year":"2014","type":"Objective","topic":"DATA MANAGEMENT : DATABASE SECURITY","question":"Which of the following methods is not suitable for securing files?","images":[],"options":{"A":"Use of back up","B":"Use of antivirus","C":"Saving documents without a password","D":"Proper labelling of storage devices"},"answer":"C","explanation":"Securing files involves protecting them from unauthorized access, loss, or damage. While using backups, antivirus software, and proper labeling of storage devices can help secure files, saving documents without a password does not provide any security. It allows anyone who can access the storage location to open and potentially modify the document. Therefore, saving documents without a password is not a suitable method for securing files.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>19","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : CLASSIFICATION OF COMPUTERS","question":"Which of the following programming languages needs no translator for it to run?","images":[],"options":{"A":"High Level Language","B":"Low Level Language","C":"Machine Language","D":"Assembly Language"},"answer":"C","explanation":"Machine language is the only programming language that a computer can understand without a translator. It is written in binary and is directly executed by the computer. High-level languages and assembly languages need to be translated into machine language before they can be run. Therefore, machine language is the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>20","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Fig. 2 is a System Development Cycle. Use it to answer this question      The path labeled I is the","images":["data:image/png;base64,"],"options":{"A":"system design","B":"system implementation","C":"study review","D":"feasibility study"},"answer":"D","explanation":"The path labeled 'I' represents the feasibility study, an essential step in the software development life cycle (SDLC). A feasibility study is a comprehensive analysis that evaluates the practicality and viability of a proposed software project, considering factors such as technical feasibility, economic feasibility, legal feasibility, and operational feasibility.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>21","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Fig. 2 is a System Development Cycle. Use it to answer this question    The path labeled II is the","images":["data:image/png;base64,"],"options":{"A":"system design","B":"system implementation","C":"study review","D":"feasibility study"},"answer":"A","explanation":"The path labeled 'II' represents the system design phase of the software development life cycle (SDLC). System design involves creating a detailed blueprint of the software system, outlining its architecture, components, and interactions. This phase ensures that the software meets the specified requirements and is technically feasible.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>22","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Fig. 2 is a System Development Cycle. Use it to answer this question    The path labeled III is the","images":["data:image/png;base64,"],"options":{"A":"system design","B":"study review","C":"system implementation","D":"feasibility study"},"answer":"C","explanation":"The path labeled 'III' represents the system implementation phase of the software development life cycle (SDLC). System implementation involves translating the system design into a working software product. This phase includes coding, testing, and integrating the various components of the software.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>23","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Fig. 3 is a flowchart. Use it to answer this question.      The part labeled I represents","images":["data:image/png;base64,"],"options":{"A":"begin/start symbol","B":"process/action symbol","C":"read/write symbol","D":"stop/end symbol"},"answer":"C","explanation":"The symbol labeled 'I' within the flowchart represents a read/write operation, indicating a step where data is either inputted into the system or outputted from the system.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>24","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Fig. 3 is a flowchart. Use it to answer this question.    The part labeled II represents","images":["data:image/png;base64,"],"options":{"A":"decision symbol","B":"read/write symbol","C":"process symbol","D":"stop/end symbol"},"answer":"C","explanation":"The symbol labeled 'II' within the flowchart represents a process step, indicating an action or operation that is performed within the process. This symbol is typically used to represent tasks, activities, or decision points.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>25","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION PROCESSING : THE ART OF INFORMATION PROCESSING","question":"Fig. 3 is a flowchart. Use it to answer this question.    The part labelled III represents","images":["data:image/png;base64,"],"options":{"A":"process/action symbol","B":"decision symbol","C":"read/write symbol","D":"stop symbol"},"answer":"B","explanation":"The symbol labeled 'III' within the flowchart represents a decision step, indicating a point in the process where a choice or evaluation is made. This symbol is typically used to represent decision points that determine the flow of the process based on specific conditions or criteria.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>26","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"The acronym HTTP stands for","images":[],"options":{"A":"Hyper Text Transfer Protocol","B":"Higher Transfer Text Protocol","C":"Hard Text Transfer Protocol","D":"Higher Text Transfer Protocol"},"answer":"A","explanation":"HTTP stands for Hyper Text Transfer Protocol. It is the protocol used for transferring hypertext requests and information on the internet. Hypertext is structured text that uses logical links (hyperlinks) between nodes containing text. Therefore, the correct answer is Hyper Text Transfer Protocol.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>27","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION TRANSMISSION : NETWORKING","question":"In ring topology, the computer that is allowed to transmit data possesses the","images":[],"options":{"A":"packet","B":"data","C":"access method","D":"token"},"answer":"D","explanation":"In a ring topology, the computer that is allowed to transmit data possesses the 'token'. A token is a special type of frame that is passed around the network from one node to the next. Only the node that holds the token can transmit data. Once the data transmission is complete, the token is released back into the network for other nodes to use.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>28","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"The most cost effective and secure way of transmitting confidential messages among the employees of an organization is the","images":[],"options":{"A":"electronic notice boards","B":"teleconferencing","C":"e-mail","D":"social networks"},"answer":"C","explanation":"E-mail is the most cost effective and secure way of transmitting confidential messages among the employees of an organisation.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>29","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The application software which allows information available on the internet to be obtained is called","images":[],"options":{"A":"browser","B":"world wide web","C":"spreadsheet","D":"internet protocol"},"answer":"A","explanation":"The application software which allows information available on the internet to be obtained is called a 'browser'. A web browser is a software application that people use to access the World Wide Web. It translates the coding language of the web into the text, graphics, and other features that we see.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>30","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION TRANSMISSION : INTERNET","question":"A modem and a telephone connection are provided. Other things needed to be able to connect a computer to the internet are","images":[],"options":{"A":"ISP account and utility software","B":"browser and ISP account","C":"ISP account and network","D":"browser and printer"},"answer":"B","explanation":"To connect a computer to the internet, you need an Internet Service Provider (ISP) account, which provides you with access to the internet, and a browser, which is a software application used to locate, retrieve and display content on the World Wide Web, including Web pages, images, video and other files.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>31","subject":"Computer Studies","year":"2014","type":"Objective","topic":"INFORMATION TRANSMISSION : MEDIUM OF INFORMATION TRANSMISSION","question":"Which of the following is employed in transfer of data between computers and a network?","images":[],"options":{"A":"Fiber optic","B":"Male connector","C":"Female connector","D":"USB Port"},"answer":"A","explanation":"Fiber optic cables are used in the transfer of data between computers and a network. They transmit information as light, and are capable of transmitting large amounts of data at high speeds over long distances. They are less susceptible to interference and are faster than traditional copper cables.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>32","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : GRAPHIC PACKAGES","question":"Which of the following software can be used for graphic production","images":[],"options":{"A":"DOS editor","B":"PC writer","C":"Corel draw","D":"Acrobat reader"},"answer":"C","explanation":"Corel Draw is a vector graphics editor developed and marketed by Corel Corporation. It is also the name of the Corel graphics suite, which includes the bitmap-image editor Corel Photo-Paint as well as other graphics-related programs. It is used for graphic production.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>33","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"In word processing, the icon in Fig. 4 is used for","images":["data:image/png;base64,"],"options":{"A":"paging","B":"line spacing","C":"numbering","D":"bulleting"},"answer":"C","explanation":"The icon depicted in Figure 4 is commonly used in word processing applications to insert numbered lists. This feature allows users to automatically assign sequential numbers to items within a list, enhancing readability and organization.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>34","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : WORD PROCESSING","question":"Which of the following items is not located on the MS Word menu bar?","images":[],"options":{"A":"Home","B":"Open","C":"View","D":"Mailings"},"answer":"B","explanation":"The Open option is not located on the MS Word menu bar. It is typically found in the Quick Access Toolbar or File menu. The Home, View, and Mailings tabs are all located on the menu bar and contain various commands for formatting, viewing, and managing documents.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>35","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400    In Table 3, the content of cell C5 is","images":[],"options":{"A":"2456","B":"4009","C":"4400","D":"3450"},"answer":"B","explanation":"The question asks for the content of cell C5 in the given table. In spreadsheet terminology, cell references are given as a combination of the column letter and the row number. So, cell C5 refers to the cell in the third column (C) and the fifth row (5). Looking at the table, the content of cell C5 is '4009', which matches option 2.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>36","subject":"Computer Studies","year":"2014","type":"Objective","topic":"TOOLS FOR PROCESSING INFORMATION : SPREADSHEET","question":"Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400  The number of cells that contain data in row 1 is","images":[],"options":{"A":"1","B":"3","C":"5","D":"7"},"answer":"C","explanation":"The question asks for the number of cells that contain data in row 1 of the given table. In spreadsheet terminology, a row is a horizontal line, and a cell is a box where a row and column intersect. Looking at the table, row 1 contains the following data: 'BOOKS', 'SUPPLIED', 'TO SENIOR', 'HIGH', 'SCHOOLS'. Therefore, there are 5 cells in row 1 that contain data, which matches option 3.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>37","subject":"Computer Studies","year":"2014","type":"Objective","topic":"DATA MANAGEMENT : RELATIONAL MODEL","question":"Use Table 3 to answer this question.  ABCDE1BOOKSSUPPLIEDTO SENIORHIGHSCHOOLS2MATHSICTENGLISH3SHS I3450450056783SHS II8765658090005SHS III245640094400  Which of the cells in Table 3 contains numeric data with the least value?","images":[],"options":{"A":"A5","B":"B5","C":"C5","D":"D5"},"answer":"B","explanation":"The provided table shows that cell B5 contains the numeric data with the lowest value. Comparing the numerical values in all the cells, it is clear that 2456 is the smallest among them, indicating that it is the cell with the least value.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>38","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"In changing the storage location of a file, the command to use is","images":[],"options":{"A":"ctrl + S keys","B":"'save' command","C":"'save as' command","D":"Alt + f, then save"},"answer":"C","explanation":"'Save as' command is used to change the storage location of a file. This command allows you to specify a new location and name for the file. The 'ctrl + S keys' and 'save' command are used to save changes to the current file in its current location. 'Alt + f, then save' is a keyboard shortcut to save a file, not to change its location.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>39","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"Which of the following statements is true about registers?","images":[],"options":{"A":"It is a storage area around CPU","B":"It is situated beside the CPU","C":"It is situated beside the memory","D":"It is a special high speed storage area within the CPU"},"answer":"D","explanation":"Registers are a special high-speed storage area within the CPU. They are the smallest and fastest storage area in the computer. The CPU uses registers to store data that is being processed. The other options are incorrect because registers are not situated around or beside the CPU or memory, they are inside the CPU.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>40","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The instruction fetched into the CPU is decoded by the","images":[],"options":{"A":"primary memory","B":"program counter","C":"ALU","D":"Control Unit"},"answer":"D","explanation":"The Control Unit of the CPU is responsible for decoding instructions. It interprets the instructions and initiates the necessary actions to execute them. The primary memory holds the instructions and data, the program counter keeps track of the address of the next instruction to be executed, and the ALU (Arithmetic Logic Unit) performs arithmetic and logical operations.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>41","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : COMPONENTS OF COMPUTERS","question":"The process of restarting a computer is known as","images":[],"options":{"A":"cold booting","B":"warm booting","C":"resume booting","D":"restart booting"},"answer":"B","explanation":"Warm booting is the process of restarting a computer.","marks":"1","difficulty":"1"},{"id":"objective>Computer Studies>2014>42","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Evaluate the BASIC statement  LET Z = 4*W2 + 2*y given that W = 5 and Y = 10.","images":[],"options":{"A":"50","B":"8","C":"100","D":"120"},"answer":"D","explanation":"The BASIC statement can be evaluated by substituting the given values of W and Y into the equation. So, Z = 4*5^2 + 2*10 = 4*25 + 20 = 100 + 20 = 120. Therefore, the correct answer is 120.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>43","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"Given that 2610 = (X)2, X is","images":[],"options":{"A":"11011","B":"11010","C":"11110","D":"10111"},"answer":"B","explanation":"The decimal number 26 can be converted to binary by dividing by 2 and recording the remainder until the quotient is 0. The binary equivalent of 26 is 11010. Therefore, the correct option is 2.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>44","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"In hexadecimal number system, B, D, F represent","images":[],"options":{"A":"11, 12, 13 respectively","B":"11, 13, 15 respectively","C":"13, 14, 15 respectively","D":"14, 16, 17 respectively"},"answer":"B","explanation":"A = 10, B = 11, C = 12, D =13, E = 14, F = 15  B, D, F = 11, 13, 15 respectively","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>45","subject":"Computer Studies","year":"2014","type":"Objective","topic":"BASIC COMPUTING : APPLICATION OF ICT IN EVERYDAY LIFE","question":"The conversion of 110012 to base 10 equals","images":[],"options":{"A":"30","B":"28","C":"25","D":"20"},"answer":"C","explanation":"110012 to base 10  14130201  (1 \u00d7 24) + (1 \u00d7 23) + (0 \u00d7 22) + (0 \u00d7 21) + (1 \u00d7 20)  16 + 8 + 0 + 0 + 1  25","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>46","subject":"Computer Studies","year":"2014","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"The transaction file can also be described as","images":[],"options":{"A":"master file","B":"movement file","C":"reference file","D":"historical file"},"answer":"B","explanation":"A transaction file is a file that is used to update a master file in a batch processing system. It contains records of transactions that occur, such as sales or purchases. This is why it is also referred to as a movement file, as it records the movement of transactions.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>47","subject":"Computer Studies","year":"2014","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"Which of the following statements is not true about a computer file?","images":[],"options":{"A":"It is very fast to access any record within a file","B":"It is created electronically","C":"Initial setup is expensive","D":"File creation and access are less laborious"},"answer":"A","explanation":"While computer files can be accessed quickly, the speed of access can vary depending on the size of the file and the method of access used. For example, sequential access (where records are accessed one after the other in order) can be slower than direct access (where any record can be accessed directly without having to go through other records).","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>48","subject":"Computer Studies","year":"2014","type":"Objective","topic":"DATA MANAGEMENT : FILE ORGANIZATION","question":"An advantage of sequential access over serial access is that","images":[],"options":{"A":"sequential file is slow","B":"sequential file is detailed","C":"sequential file does not use key","D":"individual records can be located more quickly"},"answer":"D","explanation":"Sequential access means that records are accessed one after the other in a specific order, usually based on a key field. This can make it quicker to locate individual records compared to serial access, where records are accessed in the order they were entered, without any specific order.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>49","subject":"Computer Studies","year":"2014","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER ETHICS","question":"The use of electronic systems to send an unsolicited e-mail to someone's address is known as","images":[],"options":{"A":"hacking","B":"spamming","C":"internet fraud","D":"piracy"},"answer":"B","explanation":"Spamming is the practice of sending unwanted, unsolicited digital messages, especially advertising messages to a group of recipients. In this context, the question refers to the act of sending unsolicited emails, which is known as spamming.","marks":"1","difficulty":"2"},{"id":"objective>Computer Studies>2014>50","subject":"Computer Studies","year":"2014","type":"Objective","topic":"ETHICS AND HUMAN ISSUES : COMPUTER ETHICS","question":"Which of the following ideals is protected by copyright?","images":[],"options":{"A":"Ideas","B":"Profit","C":"Expression of Ideas","D":"Inexperience"},"answer":"C","explanation":"Copyright protects the expression of ideas, not the ideas themselves. This means that if you have a unique way of expressing an idea, that expression is protected by copyright. However, the underlying idea itself is not protected, and others are free to express that same idea in their own unique ways.","marks":"1","difficulty":"2"}];